// ================================================================
// BUILD THE QUOTE HTML
//
// This node takes one form submission and turns it into the HTML
// page that becomes the PDF quote.
//
// It is safe to edit this code. The places you are most likely
// to change are marked with:  CHANGE ME
// ================================================================


// ---- STEP 1: Get the incoming data -----------------------------
// "data" holds the form answers PLUS the settings from the
// "Set Configuration Parameters" node.
const data = $input.first().json;


// ---- STEP 2: Helper that keeps the HTML safe --------------------
// Converts characters like < and & so that whatever the prospect
// typed into the form cannot break the quote layout.
// Rule of thumb: wrap ANY text you print in the HTML in esc(...).
function esc(text) {
  return String(text ?? '')
    .replaceAll('&', '&amp;')
    .replaceAll('<', '&lt;')
    .replaceAll('>', '&gt;')
    .replaceAll('"', '&quot;')
    .replaceAll("'", '&#39;');
}


// ---- STEP 3: Read the form answers ------------------------------
// The names in ['...'] must match the form field labels in the
// trigger node EXACTLY. If you rename a form field there,
// rename it here too.                                  CHANGE ME
const customerName  = data['Full name']        || 'Customer';
const customerEmail = data['Email']            || '';
const request       = data['What do you need'] || '';
const budget        = data['Estimated budget'] || 'Not specified';


// ---- STEP 4: Create the quote number and validity date ----------
// Example quote number: QTE-20260710-4821
const today = new Date().toISOString().slice(0, 10);   // e.g. 2026-07-10
const quoteNumber = 'QTE-' + today.replaceAll('-', '') + '-' + String(Date.now()).slice(-4);

// How many days the quote stays valid (set in Set Configuration Parameters)
const validityDays = Number(data.quoteValidityDays) || 30;
const validUntil = new Date(Date.now() + validityDays * 24 * 60 * 60 * 1000)
  .toISOString().slice(0, 10);


// ---- STEP 5: The quote itself ------------------------------------
// This is normal HTML and CSS. Change colors, fonts, and layout
// in the <style> block below.                          CHANGE ME
const html = `<!DOCTYPE html>
<html>
<head>
<style>
  body     { font-family: Arial, sans-serif; padding: 40px; color: #1e293b; }
  h1       { margin: 0 0 4px 0; }
  h2       { color: #64748b; margin: 0 0 24px 0; font-weight: 600; }
  .meta p  { margin: 4px 0; }
  .request { margin: 24px 0; padding: 16px; background: #f8fafc; border-left: 3px solid #cbd5e1; white-space: pre-wrap; }
  .note    { color: #64748b; font-size: 14px; margin-top: 32px; }
</style>
</head>
<body>

  <h1>${esc(data.companyName || 'Your Company Inc.')}</h1>
  <h2>QUOTE</h2>

  <div class="meta">
    <p><strong>Quote #:</strong> ${quoteNumber}</p>
    <p><strong>Date:</strong> ${today}</p>
    <p><strong>Valid until:</strong> ${validUntil}</p>
    <p><strong>Prepared for:</strong> ${esc(customerName)} (${esc(customerEmail)})</p>
    <p><strong>Estimated budget:</strong> ${esc(budget)}</p>
  </div>

  <h3>Your request</h3>
  <div class="request">${esc(request)}</div>

  <p class="note">${esc(data.hourlyRateNote || '')}</p>

</body>
</html>`;


// ---- STEP 6: Hand everything to the next nodes -------------------
// "html" becomes the PDF. The other fields are used by the two
// email nodes (the quote email and the follow-up).
return [{
  json: {
    html: html,
    quoteNumber: quoteNumber,
    customerName: customerName,
    customerEmail: customerEmail,
    validUntil: validUntil,
    quoteFilename: quoteNumber + '.pdf'
  }
}];
